commits.content:
.chat-icon {
  position: fixed;
  bottom: 24px;
  right: 24px;
  background: #007bff;
  color: white;
  border-radius: 50%;
  padding: 16px;
  cursor: pointer;
  font-size: 24px;
  z-index: 999;
  box-shadow: 0 2px 8px rgba(0,0,0,0.2);
}

.chat-window {
  position: fixed;
  bottom: 90px;
  right: 24px;
  width: 300px;
  background: white;
  border-radius: 8px;
  box-shadow: 0 2px 12px rgba(0,0,0,0.3);
  display: flex;
  flex-direction: column;
  z-index: 999;
}

.chat-header {
  background: #007bff;
  color: white;
  padding: 8px;
  font-weight: bold;
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-top-left-radius: 8px;
  border-top-right-radius: 8px;
}

.chat-body {
  max-height: 250px;
  overflow-y: auto;
  padding: 8px;
  display: flex;
  flex-direction: column;
}

.chat-body .user {
  text-align: right;
  margin: 4px 0;
  color: #333;
}

.chat-body .bot {
  text-align: left;
  margin: 4px 0;
  color: #007bff;
}

.chat-input {
  display: flex;
  padding: 8px;
  border-top: 1px solid #ccc;
}

.chat-input input {
  flex: 1;
  padding: 6px;
  border-radius: 4px;
  border: 1px solid #ccc;
  margin-right: 4px;
}

.chat-input button {
  background: #007bff;
  color: white;
  border: none;
  padding: 6px 12px;
  border-radius: 4px;
  cursor: pointer;
}
